var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"이터니움 내부 카르마 오염도 99%. 사용 불가 판정.","JPN":"エタニウム内部カルマ汚染度99％。使用不可判定。","ENG":"Internal karma contamination of Eternium at 99%. Resource deemed unusable.","TWN":"永恆之金內部\\"業力\\"污染度99%，已無法使用。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"테라사이드 시스템을 통한 윤회 정화 가능성 계산 중.","JPN":"テラサイドシステムによる輪廻浄化の可能性を計算中。","ENG":"Calculating the feasibility of samsara purification via the Terraside system.","TWN":"正在計算特拉賽德系統迴圈的淨化可能性。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"계산 결과 — ","JPN":"計算結果——","ENG":"Feasibility calculation results: ","TWN":"計算結果 —"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>희박</color>","JPN":"<color=#ffd34c>極めて低い</color>","ENG":"<color=#ffd34c>Highly unlikely.</color>","TWN":"<color=#ffd34c>渺茫</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"제 6차 얼터니움 정제 실험 — 개시.","JPN":"第6次オルタニウム精製実験——開始。","ENG":"Commencing the sixth Alternium refining test.","TWN":"第6次黑化永恆之金實驗 — 開始。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"몇 번이나 설명을 들었지만 여전히 납득하기 어렵군요.","JPN":"何度も説明を聞いてはいますが、やはり理解しがたいですね。","ENG":"I heard the explanation many times over, but I still find it hard to believe.","TWN":"雖然已經聽了很多次，但還是無法理解。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정말 가능하신 건가요?","JPN":"本当に可能なのでしょうか？","ENG":"Are you sure you can pull this off?","TWN":"真的能行的通嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"걱정 말고 커피나 한 잔 하면서 기다리게.","JPN":"心配することないさ。コーヒーでも飲みながら待とう。","ENG":"Stop your worrying and have some coffee while you wait.","TWN":"不用擔心，一邊喝咖啡一邊等吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이래 봬도 왕년에는 꽤 잘나가는 관리자였어.","JPN":"こう見えてもかつては凄腕の管理者だったんだ。","ENG":"I was a pretty successful Administrator at one point, you know.","TWN":"別忘了，我當年可是非常優秀的管理者。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇게 잘나가서 구 관리국을 폭삭 말아먹고 앞날이 창창한 소녀 하나는 애꾸눈 청년 실업자로 만드셨죠.","JPN":"その凄腕のおかげで旧管理局が崩壊し、将来有望だったある少女は、眼帯の失業者になりましたね。","ENG":"Sure, until you ran the Old Administration into the ground and turned a promising young girl into an unemployed, one-eyed loser.","TWN":"是啊，把舊管理局弄得一塌糊塗，還把一個前途無量的少女變成了獨眼失業者。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그때 생각을 하니 지금도 혈압이 치솟는군요.","JPN":"あの時のことを思い出すと血圧が上がりそうです。","ENG":"Thinking about that makes my blood boil again.","TWN":"一想到那個時候，我就火冒三丈。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......크흠. 고, 고생하긴 나도 마찬가지 아닌가.","JPN":"……ゴホン。く、苦労したのはお互い様じゃないか。","ENG":"... Ahem. W-well, those were tough times for me as well.","TWN":"……呃，說、說到辛苦，我不也一樣辛苦嗎。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"서로 알 거 다 아는 사이에 그렇게 말하니 섭섭하군.","JPN":"多くの逆境を共に乗り越えてきた仲なのに、寂しいことを言うな。","ENG":"I thought you and I had become close enough to get past all that.","TWN":"我們都這麼熟了，你那樣說真是太讓人傷心了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 됐습니다.","JPN":"まあ、いいでしょう。","ENG":"Oh well, whatever.","TWN":"嗯，那就算了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지금 중요한 건 저 쓸모없는 폐기물을 다시 쓸 수 있는지니까요.","JPN":"今大事なのはあのオンボロの廃棄物を使い物にできるかどうかですから。","ENG":"What's important right now is whether we can make that piece of junk usable again.","TWN":"現在重要的是想辦法重新使用那個垃圾。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"기껏 그림자 침식체를 사냥해서 얻은 이터니움이 폐기 판정이라니......","JPN":"せっかくシャドウの侵食体を倒して手にしたエタニウムが廃棄判定だなんて……","ENG":"I can't believe we went through all the trouble of hunting Shadows only to end up with Eternium marked for disposal…","TWN":"拼命獵殺暗影侵蝕體獲得的永恆之金竟然是垃圾……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하나 씨가 이 사실을 알면 당장 제 법인카드부터 압수할 겁니다.","JPN":"ナカシマさんに知られたら、真っ先に私の法人カードから押収すると思いますよ。","ENG":"If Hana finds out, she'll confiscate my corporate credit card.","TWN":"要是讓金荷娜知道了，肯定會當場沒收我的公司信用卡的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럴 것까지야. 관리국은 폐기 판정된 이터니움도 모두 사들이고 있다네.","JPN":"そこまではしないだろう。管理局は廃棄判定のエタニウムでもすべて買い付けている。","ENG":"Oh, it's not that bad, really. The Administration buys Eternium marked for disposal too.","TWN":"不至於吧。管理局可是將被判定為垃圾的永恆之金也全部收購呢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"함선 운용비도 안 나오는 헐값으로 말이죠.","JPN":"艦船の運用費用も回収できない安値で、ですね。","ENG":"Yeah, and they barely pay enough to keep the ships afloat.","TWN":"這些都不夠用來維持艦船的運營費用呢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>내</color> 이터니움을 그따위 가격에 후려치려는 강도 놈들은 구 관리국 에이스의 분노가 얼마나 무자비한지 알게 될 겁니다.","JPN":"<color=#ffd34c>私の</color>エタニウムをそんな安値で買い叩こうとすれば、旧管理局エースの怒りが\\nどれほど無慈悲なものか、身をもって知ることになるでしょう。","ENG":"Those bandits will feel this Old Administration's ace Counter's wrath if they dare slash the price of <color=#ffd34c>my</color> Eternium like that.","TWN":"那幫強盜竟然如此壓低<color=#ffd34c>我的</color>永恆之金價格，我會讓他們知道舊管理局王牌的怒火是多麼無情。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그러니 건성으로 하지 마시고 제값 받을 수 있게 최선을 다해 주시죠.","JPN":"だからいい加減な態度はやめて、しっかり適正価格で売れるように最善を尽くしてくださいね。","ENG":"Please try your best to ensure it fetches a fair price, instead of slacking off like you usually do.","TWN":"所以，別敷衍了事，一定要盡全力修復，賣出好價錢來。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그거 못 팔면 이번 분기도 얄짤없이 적자입니다.","JPN":"そうでもしなければ、今期も赤字確定ですから。","ENG":"If we don't manage to sell that, we're going to be in the red again this quarter.","TWN":"如果賣不出去，那這個季度也虧本了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"참 이상하단 말이지. 회사 수익은 계속 높아지고 있는데 왜 적자에선 못 벗어나는 건가?","JPN":"それにしても不思議だな。会社の収益は徐々に増えてきているのに、なぜ我が社は赤字から脱却できないのだ？","ENG":"It's odd, isn't it? Our revenues keep going up, so why is the company still in the red?","TWN":"也真是奇怪。公司的收入一直都在提高，為什麼就無法擺脫赤字呢？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"주된 원인으로는 현장에서 끊이지 않는 사유재산 파손과 보급품 남용......","JPN":"主な原因としては、現場で絶えない私有財産の破損と補給品の乱用……","ENG":"Mainly because of collateral damage and the unauthorized use of supplies on site...","TWN":"主要原因是執行任務過程中發生的私有財產損壞和補給品濫用……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그리고 머신 갑 사진집 출판 등이 있겠군요.","JPN":"そして「マシーン-甲-」の写真集出版などが原因ですね。","ENG":"And the costs of publishing Machine G.A.P.'s photo collection.","TWN":"加上「機械·我超帥」寫真集發行…等之類的費用呢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......사진집은 자비 출판일세.","JPN":"……写真集は自費出版だったはずだ。","ENG":"... I'm paying for that photo collection out of my pocket.","TWN":"……發行寫真集是自費的。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러면 통화는 이쯤에서 끝내지. 아까부터 기다리는 사람이 있어서 말이야.","JPN":"通話はこれくらいにしよう。さきほどから待たせている人がいてね。","ENG":"I'm afraid we'll have to wrap up this call now. Someone's been waiting for me.","TWN":"先講到這裡吧，我這裡還有點事情。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미안하군. 급한 업무 전화라.","JPN":"すまないな。急な業務連絡で。","ENG":"Sorry about that. It was an urgent work call.","TWN":"抱歉，剛剛打來緊急業務電話。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"RITA_HORIZON_NULL_Q","text":{"KOREA":"사과할 필요 없어. 혼자 마시는 것도 슬슬 지루해지던 참이었으니까.","JPN":"謝ることはないさ。一人で飲むのもそろそろ飽きてきた頃だ。","ENG":"No need to apologize. I was getting bored drinking by myself anyway.","TWN":"不用道歉。一個人喝東西也漸漸有點無聊了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"RITA_HORIZON_NULL_Q","text":{"KOREA":"손님도, 바텐더도...... 심지어 좋은 음악도 없는 술집이면 소란스럽기라도 해야지.","JPN":"客も、バーテンダーも……良い音楽すらないバーなら、騒がしい雰囲気でも肴にして飲まないとな。","ENG":"This bar has no other customers, or even a bartender... Hell, they don't even play any music. So a rowdy phone call is welcome noise.","TWN":"沒顧客，沒調酒師……甚至連個好音樂都沒有就算了，作為酒吧起碼要有點交談的吵雜聲吧。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_Q","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"RITA_HORIZON_NULL_Q","text":{"KOREA":"그래서 넌 뭐지? 누가 리타란 년한테 안부라도 전해 달라던가?","JPN":"で、お前は何者だ？　誰かに私が元気にしてるか確かめてほしいとでも頼まれたのか？","ENG":"So who the hell are you? Did someone ask you to say hello to some broad named Rita?","TWN":"那你現在是？有人要你來跟一個叫\\"麗塔\\"的女人問好嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"유감스럽게도 아니야. 이런 곳에서 말을 거는 사람은 둘 중 하나지.","JPN":"残念ながらハズレだ。こんな所で話しかける理由は二つに一つだろう。","ENG":"Regrettably, no. There are two types of people who strike up a conversation in a place like this.","TWN":"很遺憾，不是，在這種地方會搭訕的人無非就只有兩種。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"호의로 술 한 잔 사고 싶거나, 분위기를 띄울 얘기를 듣고 싶거나.","JPN":"好意で一杯奢りたいか、盛り上がる話を聞きたいか、だ。","ENG":"They either want to gain your favor by buying you a drink, or genuinely want some good conversation to lighten the mood.","TWN":"一是出於好意請客喝杯酒，二是想聽點能活絡氣氛的話題。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_Q","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래? 넌 어느 쪽이지?","JPN":"それで？　お前はどっちだ？","ENG":"Really? And which type are you?","TWN":"是嗎？那你是哪種？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"공교롭게도 둘 다로군.","JPN":"もちろん、どちらもだ。","ENG":"I happen to be both.","TWN":"碰巧，兩種都是。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"럼은 어때? 아니면 역시 위스키?","JPN":"ラムはどうだ？　それともやはりウイスキーか？","ENG":"How about some rum? Or is it whiskey... as usual?","TWN":"蘭姆酒怎麼樣？還是要來點威士忌？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"위스키. 싱글 배럴 버번으로.","JPN":"ウイスキー。シングルバレルバーボンで。","ENG":"Whiskey. Single barrel bourbon.","TWN":"威士忌，單桶波本威士忌。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"취향이 훌륭한걸. 여기 있네.","JPN":"素晴らしい選択だ。さあ、どうぞ。","ENG":"Excellent choice. Here you go.","TWN":"品味挺不錯，給你。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너처럼 겁없는 녀석은 간만이군.","JPN":"お前みたいな肝が据わっている男は久しぶりだ。","ENG":"It's been a while since I've met someone with balls.","TWN":"好久沒碰到像你這樣不知死活的傢伙了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L10_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"사업차 만나는 고객들은 나와 눈만 마주쳐도 도망치기 바쁘거든.","JPN":"仕事上、顧客に会いに行くことが多いんだが、目が合うだけで逃げるのに必死になる客が多くてね。","ENG":"The \\"clients\\" I meet on business tend to bail the moment we lock eyes.","TWN":"事業上有往來的顧客一看到我都會落荒而逃。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하하, 인간 관계가 그렇게 원만하진 않았나 본데.","JPN":"ハハハ、人間関係が円満ではなさそうだな。","ENG":"Hah hah, it sounds like you're not the most sociable person.","TWN":"哈哈，看來你的人際關係不怎麼好啊。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그럴 수밖에. 빌린 돈 받으러 다니는 게 내 직업이니까.","JPN":"仕方ないさ。借金の回収が私の仕事なんだから。","ENG":"Can't blame them. It's my job to collect the money they owe.","TWN":"沒辦法，因為我的工作就是收回那些借出去的錢。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"현관에 폭탄이라도 숨겨 놓고 기다리지 않는 이상 두 팔 벌려 환영할 이유가 없지.","JPN":"玄関に爆弾でも仕込んで待たない限り、歓迎する理由なんてないだろう。","ENG":"There's no reason anyone would welcome me into their homes, unless they've got a booby trap set up in the doorway.","TWN":"除非在家門口放了炸彈等我，不然誰會想要熱情的歡迎我。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런, 대부업 쪽 사람이었나? 앞으로도 신세 질 일 없길 바라겠네.","JPN":"おや、貸金業の人だったか。今後お世話になることがないように願わねばな。","ENG":"Oh, I didn't know you were in... the private financial business. I hope I'll never require your company's service.","TWN":"哎呀，你是借貸公司的？希望我們以後不會有業務上的糾葛。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러면 그 <color=#ffd34c>사업</color>은 혼자서 하는 건가?","JPN":"その<color=#ffd34c>事業</color>は一人でやり繰りしているのかね？","ENG":"So... do you run this <color=#ffd34c>business</color> on your own?","TWN":"那麼這個<color=#ffd34c>事業</color>是你一個人在做嗎？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아니. 대표는 다른 친구야.","JPN":"いや。代表は他にいる。","ENG":"No. Someone else owns the business.","TWN":"不，BOSS另有其人。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그리고......","JPN":"それと……","ENG":"And...","TWN":"還有……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래. 꼬맹이도 하나 있었지. 날마다 사고만 치고 다니는.","JPN":"ああ、ガキが一人いる。毎日のようにトラブルばかり起こしているがな。","ENG":"Oh, yeah. There was this other kid. She was always up to no good.","TWN":"對了，還有一個每天就只會闖禍的小鬼。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"평소에 감정이 많이 쌓였던 모양이군. 표정부터 달라지는 걸 보니.","JPN":"色々と溜めこんでいるようだな。その表情が物語っている。","ENG":"Sounds like you've got some history with her. It shows on your face.","TWN":"看來你平時對她很不滿，神情都變了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"툭 하면 일을 귀찮게 만들었으니까.","JPN":"いつも面倒事を起こして手こずらせてくれるからね。","ENG":"She was always a nuisance, that's why.","TWN":"因為她總是把事情搞得很麻煩。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"얼마 전에도 어김없이 한 건 크게 저질러 줬지.","JPN":"この前も案の定、派手にやらかしてくれた。","ENG":"She screwed up big again just recently.","TWN":"不久前她又犯了一個大錯。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그때가 분명히......","JPN":"あの時は確か……","ENG":"Let's see... When was it again?","TWN":"那天是……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"맞아. 기억났어.","JPN":"そうだ、思い出した。","ENG":"Oh, that's right. I remember now.","TWN":"噢，想起來了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아침부터 눈이 잔뜩 내렸던...... 재수없는 날이었지.","JPN":"朝から大雪が降っていた……ツイてない日だった。","ENG":"It snowed like crazy all morning that day... A terribly unlucky day.","TWN":"是一大早就開始下雪的……倒楣的日子。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};